// Process .ts and .js output files with this function
site.process([".ts", ".js"], processor);

//The function to process every ts/js file:
function processor (file) {
    const sourceFile = file.src.path + file.src.ext;
    let content = file.content;

   //Transform the content with your favorite tool
   content = myBundler(sourceFile, content);

   //Save the result in the file
   file.content = content;
}
```

Note that `loadAssets` will load all `.ts` and `.js` files in your site. If you want to load only the main file (because all imported files will be included in this file by the bundler, you have save the other files in an ignored folder. This folder can starts with `_` (for example: `_includes`) or you can ignore them with `site.ignore("my-folder-name")`.

