Workaround.
```ts
import lume from "lume/mod.ts";
import { Page, Site } from "lume/core.ts";

const site = lume();

site.use((site: Site) => site.process([".html"], (page: Page) => page.data.foo = "bar"));
site.use((site: Site) => site.addEventListener("afterBuild", () => site.pages.forEach((page) => console.log(page.data))));

export default site;
```
```js
{ tags: [], content: "index\n", date: 2022-01-10T09:35:35.019Z, url: "/", foo: "bar" }
```

