});

/** Returns the content of a file or page */
async function getFileContent(
  site: Site,
  url: string,
  loader: Loader,
): Promise<string | Uint8Array> {
  const content = await site.getContent(url, loader);

  if (!content) {
    throw new Error(`Unable to find the file "${url}"`);
  }

